diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 4d3de76389c2..54ec2201b834 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3165,6 +3165,45 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
       if (B == D)
         return OrFactorization(B, A, C, CondLogicOr && TrueLogicOr);
     }
+    // Try to combine nested selects with icmps:
+    // select (select C, ICmp0, false), ICmp1, false -> select C, Combined, false
+    Value *InnerCond, *InnerTrue;
+    if (match(CondVal, m_Select(m_Value(InnerCond), m_Value(InnerTrue), m_Zero())) &&
+        isa<ICmpInst>(InnerTrue) && isa<ICmpInst>(TrueVal)) {
+      ICmpInst *ICmp0 = dyn_cast<ICmpInst>(InnerTrue);
+      ICmpInst *ICmp1 = dyn_cast<ICmpInst>(TrueVal);
+      if (ICmp0 && ICmp1) {
+        // First, try to combine as a range check.
+        if (Value *NewICmp = simplifyRangeCheck(ICmp0, ICmp1, /*Inverted*/ false))
+          return SelectInst::Create(InnerCond, NewICmp, FalseVal);
+        // Check for contradiction between the two icmps.
+        Value *A0 = ICmp0->getOperand(0);
+        Value *A1 = ICmp1->getOperand(0);
+        const APInt *C0, *C1;
+        if (A0 == A1 &&
+            match(ICmp0->getOperand(1), m_APInt(C0)) &&
+            match(ICmp1->getOperand(1), m_APInt(C1))) {
+          ICmpInst::Predicate Pred0 = ICmp0->getPredicate();
+          ICmpInst::Predicate Pred1 = ICmp1->getPredicate();
+          // (a slt -1) && (a eq C) where C >= 0 -> false
+          // (a eq C) && (a slt -1) where C >= 0 -> false
+          if ((Pred0 == ICmpInst::ICMP_SLT && *C0 == -1 &&
+               Pred1 == ICmpInst::ICMP_EQ && C1->sge(0)) ||
+              (Pred1 == ICmpInst::ICMP_SLT && *C1 == -1 &&
+               Pred0 == ICmpInst::ICMP_EQ && C0->sge(0))) {
+            return replaceInstUsesWith(SI, FalseVal);
+          }
+          // (a sgt -1) && (a slt -1) -> false (since ranges are disjoint)
+          // Actually sgt -1 means a >= 0, slt -1 means a <= -2, disjoint.
+          if ((Pred0 == ICmpInst::ICMP_SGT && *C0 == -1 &&
+               Pred1 == ICmpInst::ICMP_SLT && *C1 == -1) ||
+              (Pred1 == ICmpInst::ICMP_SGT && *C1 == -1 &&
+               Pred0 == ICmpInst::ICMP_SLT && *C0 == -1)) {
+            return replaceInstUsesWith(SI, FalseVal);
+          }
+        }
+      }
+    }
   }

   // We match the "full" 0 or 1 constant here to avoid a potential infinite

